import{_ as d,o as a,c as h,a2 as r}from"./chunks/framework.DIMps2S2.js";const c=JSON.parse('{"title":"交易收费","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"stock-trading/trading-fees/fee-schedule.md","filePath":"zh-CN/stock-trading/trading-fees/fee-schedule.md"}'),e={name:"stock-trading/trading-fees/fee-schedule.md"};function l(o,t,i,b,n,s){return a(),h("div",null,[...t[0]||(t[0]=[r('<h1 id="交易收费" tabindex="-1">交易收费 <a class="header-anchor" href="#交易收费" aria-label="Permalink to &quot;交易收费&quot;">​</a></h1><p>长桥香港及新加坡账户的默认标准交易费率，涵盖港股、美股、期权及融资收费，并附佣金计算示例。</p><h2 id="长桥香港" tabindex="-1">长桥香港 <a class="header-anchor" href="#长桥香港" aria-label="Permalink to &quot;长桥香港&quot;">​</a></h2><h3 id="港股市场" tabindex="-1">港股市场 <a class="header-anchor" href="#港股市场" aria-label="Permalink to &quot;港股市场&quot;">​</a></h3><p>交易佣金：0.03% × 交易金额，单笔最低 3 HKD<br> 平台费：15 HKD / 笔</p><p>第三方代收费用（按已成交交易金额计算）：</p><table tabindex="0"><thead><tr><th>费用项目</th><th>收费标准</th></tr></thead><tbody><tr><td>交收费</td><td>0.002% × 交易金额（最低 2 HKD，最高 100 HKD）</td></tr><tr><td>印花税</td><td>0.1% × 交易金额（不足 1 港元按 1 港元计，涡轮牛熊和 ETF 不收取）</td></tr><tr><td>交易费</td><td>0.00565% × 交易金额（最低 0.01 HKD）</td></tr><tr><td>交易征费</td><td>0.0027% × 交易金额（最低 0.01 HKD）</td></tr><tr><td>财汇局交易征费</td><td>0.00015% × 交易金额（最低 0.01 HKD）</td></tr></tbody></table><h3 id="美股市场" tabindex="-1">美股市场 <a class="header-anchor" href="#美股市场" aria-label="Permalink to &quot;美股市场&quot;">​</a></h3><p>交易佣金：0.0049 USD / 股，单笔最低 0.99 USD<br> 平台费：0.005 USD / 股，单笔最低 1 USD</p><p>保护规则：佣金最多收取交易金额的 0.5%，平台使用费最多收取交易金额的 0.99%。若与每笔最低收费标准冲突，以最低收费标准为准。</p><p>第三方费用：</p><table tabindex="0"><thead><tr><th>费用项目</th><th>收费标准</th></tr></thead><tbody><tr><td>交收费</td><td>0.003 USD / 股</td></tr><tr><td>SEC 费用</td><td>0.0000278 × 交易金额（仅卖单收取，最低 0.01 USD）</td></tr><tr><td>TAF 交易活动费</td><td>0.00013 USD / 股（仅卖单收取，最低 0.01 USD，最高 6.49 USD）</td></tr></tbody></table><h3 id="美股期权" tabindex="-1">美股期权 <a class="header-anchor" href="#美股期权" aria-label="Permalink to &quot;美股期权&quot;">​</a></h3><p>当期权被卖出行使时，会收取美股卖出股票的相关第三方费用。</p><h3 id="融资收费" tabindex="-1">融资收费 <a class="header-anchor" href="#融资收费" aria-label="Permalink to &quot;融资收费&quot;">​</a></h3><p>融资利率：以官网公布为准<br> 利息公式：融资金额 × 利率 × 实际融资天数 ÷ 365，最低 0.01 港元/美元</p><p>融资天数按自然日计算。账户现金结余为负数时产生利息（持仓过夜收息，日内还款不收利息）。利息当月月终收取。</p><h3 id="打新-暗盘" tabindex="-1">打新 / 暗盘 <a class="header-anchor" href="#打新-暗盘" aria-label="Permalink to &quot;打新 / 暗盘&quot;">​</a></h3><p>港股打新中签收费由香港证监会、交易所、经纪公司收取，仅在中签时收取。</p><p>暗盘交易收费与普通港股交易收费套餐及佣金状态无关，按暗盘交易收费标准正常收取。</p><hr><h2 id="长桥新加坡" tabindex="-1">长桥新加坡 <a class="header-anchor" href="#长桥新加坡" aria-label="Permalink to &quot;长桥新加坡&quot;">​</a></h2><p>新加坡政府自 2024 年 1 月 1 日起对所有费用征收 9% 的商品及服务税（GST）。</p><h3 id="港股市场-美股市场-美股期权-新加坡股市场" tabindex="-1">港股市场 / 美股市场 / 美股期权 / 新加坡股市场 <a class="header-anchor" href="#港股市场-美股市场-美股期权-新加坡股市场" aria-label="Permalink to &quot;港股市场 / 美股市场 / 美股期权 / 新加坡股市场&quot;">​</a></h3><p>收费标准与长桥香港类似，具体以官网公布为准。新交所交易货币市场基金另收取交易价值 0.001% 的清算费。</p><h3 id="融资收费-1" tabindex="-1">融资收费 <a class="header-anchor" href="#融资收费-1" aria-label="Permalink to &quot;融资收费&quot;">​</a></h3><p>利息公式：融资金额 × 利率 × 实际融资天数 ÷ 365</p><p>应计利息天数在每日新加坡标准时间下午 18:00 计算。利息次月初收取。</p><h2 id="个人费率查询" tabindex="-1">个人费率查询 <a class="header-anchor" href="#个人费率查询" aria-label="Permalink to &quot;个人费率查询&quot;">​</a></h2><p>每位用户的实际佣金、平台费和融资利率可能因账户类型、活动优惠、免佣卡等因素不同。以上为默认标准费率，仅供参考。</p><p>查询用户的个人实际费率（佣金、平台费、融资利率），向用户说明其个人适用的费率。</p><p>查看个人费率：长桥 App - 我的 - 我的费率</p><h2 id="通用规则" tabindex="-1">通用规则 <a class="header-anchor" href="#通用规则" aria-label="Permalink to &quot;通用规则&quot;">​</a></h2><ul><li>交易佣金和平台费按每笔订单单独计算，不合并</li><li>未交割交易免息，交割当天开始计息</li><li>终生免佣规则：卡券激活次日生效，免除对应市场非暗盘交易的佣金</li></ul><hr><h2 id="港股佣金计算示例" tabindex="-1">港股佣金计算示例 <a class="header-anchor" href="#港股佣金计算示例" aria-label="Permalink to &quot;港股佣金计算示例&quot;">​</a></h2><p>以下示例使用默认标准费率，实际费率以个人账户为准。</p><h3 id="交易背景" tabindex="-1">交易背景 <a class="header-anchor" href="#交易背景" aria-label="Permalink to &quot;交易背景&quot;">​</a></h3><table tabindex="0"><thead><tr><th>成交日期</th><th>交割日期</th><th>股票代码</th><th>方向</th><th>成交价格</th><th>成交数量</th><th>成交金额</th></tr></thead><tbody><tr><td>11 月 11 日</td><td>11 月 13 日</td><td>1288.HK</td><td>买入</td><td>2.98</td><td>35,000</td><td>104,300.00</td></tr><tr><td>11 月 11 日</td><td>11 月 13 日</td><td>1288.HK</td><td>买入</td><td>2.99</td><td>2,000</td><td>5,980.00</td></tr><tr><td>11 月 12 日</td><td>11 月 14 日</td><td>1288.HK</td><td>卖出</td><td>3.02</td><td>30,000</td><td>90,600.00</td></tr><tr><td>11 月 12 日</td><td>11 月 14 日</td><td>1288.HK</td><td>卖出</td><td>3.02</td><td>6,000</td><td>18,120.00</td></tr></tbody></table><h3 id="佣金和平台费" tabindex="-1">佣金和平台费 <a class="header-anchor" href="#佣金和平台费" aria-label="Permalink to &quot;佣金和平台费&quot;">​</a></h3><p>11 月 11 日买入（每笔独立计算）：</p><table tabindex="0"><thead><tr><th>成交金额</th><th>交易佣金</th><th>平台费</th></tr></thead><tbody><tr><td>104,300.00</td><td>31.29</td><td>15</td></tr><tr><td>5,980.00</td><td>3.00（最低）</td><td>15</td></tr></tbody></table><p>11 月 12 日卖出：</p><table tabindex="0"><thead><tr><th>成交金额</th><th>交易佣金</th><th>平台费</th></tr></thead><tbody><tr><td>90,600.00</td><td>27.18</td><td>15</td></tr><tr><td>18,120.00</td><td>5.44</td><td>15</td></tr></tbody></table><h3 id="第三方收费" tabindex="-1">第三方收费 <a class="header-anchor" href="#第三方收费" aria-label="Permalink to &quot;第三方收费&quot;">​</a></h3><p>11 月 11 日买入（费率：交收 0.002%、印花税 0.1%、交易费 0.00565%、交易征费 0.0027%、财汇局 0.00015%）：</p><table tabindex="0"><thead><tr><th>成交金额</th><th>交收费</th><th>印花税</th><th>交易费</th><th>交易征费</th><th>财汇局</th><th>总计</th></tr></thead><tbody><tr><td>104,300</td><td>2.09</td><td>105</td><td>5.90</td><td>2.82</td><td>0.16</td><td>115.97</td></tr><tr><td>5,980</td><td>2.00</td><td>6</td><td>0.34</td><td>0.16</td><td>0.01</td><td>8.51</td></tr></tbody></table><p>11 月 12 日卖出：</p><table tabindex="0"><thead><tr><th>成交金额</th><th>交收费</th><th>印花税</th><th>交易费</th><th>交易征费</th><th>财汇局</th><th>总计</th></tr></thead><tbody><tr><td>90,600</td><td>2.00</td><td>91</td><td>5.12</td><td>2.45</td><td>0.14</td><td>100.71</td></tr><tr><td>18,120</td><td>2.00</td><td>19</td><td>1.03</td><td>0.49</td><td>0.03</td><td>22.55</td></tr></tbody></table><h3 id="融资利息-假设全融资-无现金" tabindex="-1">融资利息（假设全融资，无现金） <a class="header-anchor" href="#融资利息-假设全融资-无现金" aria-label="Permalink to &quot;融资利息（假设全融资，无现金）&quot;">​</a></h3><p>11 月 13 日交割买入 = 110,468.77；11 月 14 日交割卖出 = 108,534.12</p><table tabindex="0"><thead><tr><th>日期</th><th>现金余额</th><th>融资利息（按 5.75% 年利率）</th></tr></thead><tbody><tr><td>11 月 11–12 日</td><td>—</td><td>未交割免息</td></tr><tr><td>11 月 13 日</td><td>−110,468.77</td><td>110,468.77 × 5.75% ÷ 365</td></tr><tr><td>11 月 14 日</td><td>−1,934.65</td><td>1,934.65 × 5.75% ÷ 365</td></tr><tr><td>11 月 15 日</td><td>−1,934.65</td><td>1,934.65 × 5.75% ÷ 365</td></tr></tbody></table><hr><h2 id="美股佣金计算示例" tabindex="-1">美股佣金计算示例 <a class="header-anchor" href="#美股佣金计算示例" aria-label="Permalink to &quot;美股佣金计算示例&quot;">​</a></h2><p>以下示例使用默认标准费率，实际费率以个人账户为准。</p><h3 id="交易背景-1" tabindex="-1">交易背景 <a class="header-anchor" href="#交易背景-1" aria-label="Permalink to &quot;交易背景&quot;">​</a></h3><table tabindex="0"><thead><tr><th>成交日期</th><th>交割日期</th><th>股票代码</th><th>方向</th><th>成交价格</th><th>成交数量</th><th>成交金额</th></tr></thead><tbody><tr><td>7 月 11 日</td><td>7 月 13 日</td><td>CGA</td><td>买入</td><td>3.70</td><td>330</td><td>1,221.00</td></tr><tr><td>7 月 11 日</td><td>7 月 13 日</td><td>CGA</td><td>买入</td><td>3.70</td><td>30</td><td>111.00</td></tr><tr><td>7 月 12 日</td><td>7 月 14 日</td><td>CGA</td><td>卖出</td><td>3.60</td><td>330</td><td>1,188.00</td></tr><tr><td>7 月 12 日</td><td>7 月 14 日</td><td>CGA</td><td>卖出</td><td>3.60</td><td>30</td><td>108.00</td></tr></tbody></table><h3 id="佣金和平台费-1" tabindex="-1">佣金和平台费 <a class="header-anchor" href="#佣金和平台费-1" aria-label="Permalink to &quot;佣金和平台费&quot;">​</a></h3><p>7 月 11 日买入：</p><table tabindex="0"><thead><tr><th>成交数量</th><th>成交金额</th><th>交易佣金</th><th>平台费</th></tr></thead><tbody><tr><td>330</td><td>1,221.00</td><td>1.62</td><td>1.65</td></tr><tr><td>30</td><td>111.00</td><td>0.99（最低）</td><td>1.00（最低）</td></tr></tbody></table><p>7 月 12 日卖出：</p><table tabindex="0"><thead><tr><th>成交数量</th><th>成交金额</th><th>交易佣金</th><th>平台费</th></tr></thead><tbody><tr><td>330</td><td>1,188.00</td><td>1.62</td><td>1.65</td></tr><tr><td>30</td><td>108.00</td><td>0.99（最低）</td><td>1.00（最低）</td></tr></tbody></table><p><strong>低价股保护示例</strong>：买入 7,000 股（价格 0.40 USD），按股数计算佣金 = 34.30 USD，而交易金额 0.5% = 14.00 USD。因 14 &lt; 34.30，佣金按 14.00 USD 收取。</p><h3 id="第三方收费-1" tabindex="-1">第三方收费 <a class="header-anchor" href="#第三方收费-1" aria-label="Permalink to &quot;第三方收费&quot;">​</a></h3><p>7 月 11 日买入（SEC 和 TAF 仅卖单收取）：</p><table tabindex="0"><thead><tr><th>成交数量</th><th>成交金额</th><th>交收费</th><th>SEC</th><th>TAF</th><th>总计</th></tr></thead><tbody><tr><td>330</td><td>1,221.00</td><td>0.99</td><td>—</td><td>—</td><td>0.99</td></tr><tr><td>30</td><td>111.00</td><td>0.09</td><td>—</td><td>—</td><td>0.09</td></tr></tbody></table><p>7 月 12 日卖出：</p><table tabindex="0"><thead><tr><th>成交数量</th><th>成交金额</th><th>交收费</th><th>SEC</th><th>TAF</th><th>总计</th></tr></thead><tbody><tr><td>330</td><td>1,188.00</td><td>0.99</td><td>0.04</td><td>0.04</td><td>1.07</td></tr><tr><td>30</td><td>108.00</td><td>0.09</td><td>0.01</td><td>0.01</td><td>0.11</td></tr></tbody></table><h3 id="融资利息-假设全融资-无现金-1" tabindex="-1">融资利息（假设全融资，无现金） <a class="header-anchor" href="#融资利息-假设全融资-无现金-1" aria-label="Permalink to &quot;融资利息（假设全融资，无现金）&quot;">​</a></h3><p>7 月 13 日交割买入 = 1,338.34；7 月 14 日交割卖出 = 1,289.56</p><table tabindex="0"><thead><tr><th>日期</th><th>现金余额</th><th>融资利息（按 5.75% 年利率）</th></tr></thead><tbody><tr><td>7 月 11–12 日</td><td>—</td><td>未交割免息</td></tr><tr><td>7 月 13 日</td><td>−1,338.34</td><td>1,338.34 × 5.75% ÷ 365</td></tr><tr><td>7 月 14 日</td><td>−48.78</td><td>48.78 × 5.75% ÷ 365</td></tr><tr><td>7 月 15 日</td><td>−48.78</td><td>48.78 × 5.75% ÷ 365</td></tr></tbody></table><hr><p><a href="https://longbridgehk.com/calc" target="_blank" rel="noreferrer">费率计算器</a></p><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/stock-trading">股票交易</a></li><li><a href="/wiki/stock-trading/trading-fees">交易费用</a></li></ul>',75)])])}const u=d(e,[["render",l]]);export{c as __pageData,u as default};
